section Section1; shared BC_Base_URL = let BC_Base_URL = "https://api.businesscentral.dynamics.com/v2.0" meta [IsParameterQuery = true, IsParameterQueryRequired = true, Type = type text] in BC_Base_URL; shared BC_Environment = let BC_Environment = "Production" meta [IsParameterQuery = true, IsParameterQueryRequired = false, Type = type text] in BC_Environment; shared BC_Company = let BC_Company = "LVM" meta [IsParameterQuery = true, IsParameterQueryRequired = false, Type = type text] in BC_Company; [Description = "The Xxxx in Xxxx.crm.dynamics.com"] shared EnvUrlPrefix = let EnvUrlPrefix = "vjtest" meta [IsParameterQuery = true, IsParameterQueryRequired = false, Type = type any] in EnvUrlPrefix; shared Branch = let Source = OData.Feed(OData_BASEUrl & "branches?$filter=branchBlocked eq false", null, [Implementation = "2.0"]) in Source; shared Period = let Source = OData.Feed(OData_BASEUrl & "commissionPeriods", null, [Implementation = "2.0"]) in Source; shared LoanOfficer = let Source = OData.Feed(OData_BASEUrl & "commissionLoanOfficer", null, [Implementation = "2.0"]), #"From Value" = Table.FromValue(Source), #"Remove Columns" = Table.RemoveColumns(#"From Value", Table.ColumnsOfType(#"From Value", {type table, type record, type list, type nullable binary, type binary, type function})) in #"Remove Columns"; shared #"Contact (User)" = let Source = OData.Feed(OData_BASEUrl & "commissionLoanOfficer", null, [Implementation = "2.0"]),//?$filter=lvnExcludeFromWeb eq false removed aapodaca 1/13/26 #"From Value" = Table.FromValue(Source), #"Remove Columns" = Table.RemoveColumns(#"From Value", Table.ColumnsOfType(#"From Value", {type table, type record, type list, type nullable binary, type binary, type function})), #"Sorted rows" = Table.Sort(#"Remove Columns", {{"lvnFirstName", Order.Descending}}) in #"Sorted rows"; shared lv_lvcompbranch = let Source = CommonDataService.Database(EnvUrlPrefix & ".crm.dynamics.com", [CreateNavigationProperties = null]), #"Navigation 1" = Source{[Schema = "dbo", Item = "lv_lvcompbranch"]}[Data], #"Removed columns" = Table.RemoveColumns(#"Navigation 1", {"lv_modifieddate", "asyncoperation", "businessunit", "contact", "lv_lvcompcommission", "lv_lvcomploanofficer", "lv_lvcompregionbranch", "lv_lvcompregionbranchloanofficer", "processsession", "systemuser(createdby)", "systemuser(createdonbehalfby)", "systemuser(modifiedby)", "systemuser(modifiedonbehalfby)", "systemuser(owninguser)", "team", "lv_lvcompbranchid", "createdon", "createdby", "modifiedon", "modifiedby", "createdonbehalfby", "modifiedonbehalfby", "createdbyname", "createdbyyominame", "createdonbehalfbyname", "createdonbehalfbyyominame", "modifiedbyname", "modifiedbyyominame", "modifiedonbehalfbyname", "modifiedonbehalfbyyominame", "ownerid", "owneridname", "owneridyominame", "owningbusinessunit", "owninguser", "owningteam", "owningbusinessunitname", "statecode", "statecodename", "statuscode", "statuscodename", "importsequencenumber", "overriddencreatedon", "timezoneruleversionnumber", "utcconversiontimezonecode"}) in #"Removed columns"; shared lv_lvcomploanofficer = let Source = CommonDataService.Database(EnvUrlPrefix & ".crm.dynamics.com", [CreateNavigationProperties = null]), #"Navigation 1" = Source{[Schema = "dbo", Item = "lv_lvcomploanofficer"]}[Data] in #"Navigation 1"; shared OData_BASEUrl = let OData_Periods = BC_Base_URL & "/" & BC_Environment & "/ODataV4/Company('" & BC_Company & "')/" in OData_Periods; shared JournalLines = let JournalLines = BC_Base_URL & "/" & BC_Environment & "/ODataV4/Company('" & BC_Company & "')/commissionJnlLine2?$filter=hideFromWeb eq false and periodNo ge 0" in JournalLines; shared CommissionValues = let CommissionValues = BC_Base_URL & "/" & BC_Environment & "/ODataV4/Company('" & BC_Company & "')/CommissionValueEntries2?$filter=hideFromWeb eq false and periodNo ge 0" in CommissionValues; shared BC_JournalLines = let getData = (url as text) => let Source = Json.Document(Web.Contents(url)), NextLink = try Source[#"@odata.nextLink"] otherwise null, Result = if NextLink <> null then List.Combine({Source[value], @getData(NextLink)}) else Source[value] in Result,
response = getData(JournalLines),
responseCheck = if List.IsEmpty(response) then #table({"systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "regionCode", "costCenterCode", "debtLogTransactionID", "description", "expressionCode", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "lineNo", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion"}, {}) else Table.FromList(response, Splitter.SplitByNothing(), null, null, ExtraValues.Error),
columns = Table.ColumnNames(responseCheck),
expanded = if List.Contains(columns, "Column1") then Table.ExpandRecordColumn(responseCheck, "Column1", { "systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "regionCode", "costCenterCode", "debtLogTransactionID", "description", "expressionCode", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "lineNo", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion" }, { "systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "regionCode", "costCenterCode", "debtLogTransactionID", "description", "expressionCode", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "lineNo", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion" }) else responseCheck,
// Transform types safely #"Changed column type" = Table.TransformColumnTypes(expanded, { {"systemId", type text}, {"amount", type number}, {"borrowerName", type text}, {"bpsCalculated", type number}, {"businessUnitCode", type text}, {"calculationDate", type date}, {"calculationOnly", type logical}, {"calculationSchemaLineNo", Int64.Type}, {"calculationType", type text}, {"cappedCommissionBaseAmount", Int64.Type}, {"commissionBaseAmount", Int64.Type}, {"commissionDate", type date}, {"regionCode", Int64.Type}, {"costCenterCode", type text}, {"debtLogTransactionID", type text}, {"description", type text}, {"expressionCode", type text}, {"functionCode", type text}, {"globalDimension1Code", type text}, {"globalDimension2Code", type text}, {"identifierCode", type text}, {"loSplit", type number}, {"lineNo", Int64.Type}, {"loanNo", type text}, {"loanAmount", type number}, {"loanOfficerCode", type text}, {"loanOfficerType", type text}, {"loanOfficerName", type text}, {"manualEntry", type logical}, {"modifiedDateTime", type datetime}, {"period", type text}, {"periodCode", type text}, {"periodNo", Int64.Type}, {"periodCodeIdentifier", type text}, {"profileCode", type text}, {"profileName", type text}, {"shortcutDimension3Code", type text}, {"shortcutDimension4Code", type text}, {"shortcutDimension5Code", type text}, {"shortcutDimension6Code", type text}, {"shortcutDimension7Code", type text}, {"shortcutDimension8Code", type text}, {"tierChange", type logical}, {"type", type text}, {"usedForPeriodCalculation", type logical}, {"loanCardURL", type text}, {"lastDateModified", type date}, {"lastDateTimeModified", type datetime}, {"hideFromWeb", type logical}, {"systemCreated", type logical}, {"systemModifiedAt", type datetime}, {"systemCreatedAt", type datetime}, {"systemRowVersion", Int64.Type} }),
#"Added custom" = Table.AddColumn(#"Changed column type", "Region99999", each "99999", type text),
#"Inserted conditional column" = Table.AddColumn(#"Added custom", "LastDateModMin2000", each if [lastDateModified] < #date(2000, 1, 1) then #date(2000, 1, 1) else [lastDateModified], type date),
// Add composite key for Journal Lines JournalLinesWithKey = Table.AddColumn(#"Inserted conditional column", "CompositeKey", each "JL_" & [systemId], type text),
// Add source type JournalLinesWithSource = Table.AddColumn(JournalLinesWithKey, "SourceType", each "JournalLine", type text),
// Rename lineNo to JournalLineNo for JournalLines JournalLinesWithLineNo = Table.RenameColumns(JournalLinesWithSource, {{"lineNo", "JournalLineNo"}}) in JournalLinesWithLineNo; shared BC_CommissionValues = let getData = (url as text) => let Source = Json.Document(Web.Contents(url)), NextLink = try Source[#"@odata.nextLink"] otherwise null, Result = if NextLink <> null then List.Combine({Source[value], @getData(NextLink)}) else Source[value] in Result,
response = getData(CommissionValues), responseCheck = if List.IsEmpty(response) then #table({"systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "conditionCode", "regionCode", "costCenterCode", "description", "entryNo", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion"}, {}) else Table.FromList(response, Splitter.SplitByNothing(), null, null, ExtraValues.Error),
columns = Table.ColumnNames(responseCheck), expanded = if List.Contains(columns, "Column1") then Table.ExpandRecordColumn(responseCheck, "Column1", { "systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "conditionCode", "regionCode", "costCenterCode", "description", "entryNo", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion" }, { "systemId", "amount", "borrowerName", "bpsCalculated", "businessUnitCode", "calculationDate", "calculationOnly", "calculationSchemaLineNo", "calculationType", "cappedCommissionBaseAmount", "commissionBaseAmount", "commissionDate", "conditionCode", "regionCode", "costCenterCode", "description", "entryNo", "functionCode", "globalDimension1Code", "globalDimension2Code", "identifierCode", "loSplit", "loanNo", "loanAmount", "loanOfficerCode", "loanOfficerType", "loanOfficerName", "manualEntry", "modifiedDateTime", "period", "periodCode", "periodNo", "periodCodeIdentifier", "profileCode", "profileName", "shortcutDimension3Code", "shortcutDimension4Code", "shortcutDimension5Code", "shortcutDimension6Code", "shortcutDimension7Code", "shortcutDimension8Code", "tierChange", "type", "usedForPeriodCalculation", "loanCardURL", "lastDateModified", "lastDateTimeModified", "hideFromWeb", "systemCreated", "systemModifiedAt", "systemCreatedAt", "systemRowVersion" }) else responseCheck,
// Transform types safely #"Changed column type" = Table.TransformColumnTypes(expanded, { {"systemId", type text}, {"amount", type number}, {"borrowerName", type text}, {"bpsCalculated", type number}, {"businessUnitCode", type text}, {"calculationDate", type date}, {"calculationOnly", type logical}, {"calculationSchemaLineNo", Int64.Type}, {"calculationType", type text}, {"cappedCommissionBaseAmount", Int64.Type}, {"commissionBaseAmount", Int64.Type}, {"commissionDate", type date}, {"conditionCode", type text}, {"regionCode", Int64.Type}, {"costCenterCode", type text}, {"description", type text}, {"entryNo", Int64.Type}, {"functionCode", type text}, {"globalDimension1Code", type text}, {"globalDimension2Code", type text}, {"identifierCode", type text}, {"loSplit", type number}, {"loanNo", type text}, {"loanAmount", type number}, {"loanOfficerCode", type text}, {"loanOfficerType", type text}, {"loanOfficerName", type text}, {"manualEntry", type logical}, {"modifiedDateTime", type datetime}, {"period", type text}, {"periodCode", type text}, {"periodNo", Int64.Type}, {"periodCodeIdentifier", type text}, {"profileCode", type text}, {"profileName", type text}, {"shortcutDimension3Code", type text}, {"shortcutDimension4Code", type text}, {"shortcutDimension5Code", type text}, {"shortcutDimension6Code", type text}, {"shortcutDimension7Code", type text}, {"shortcutDimension8Code", type text}, {"tierChange", type logical}, {"type", type text}, {"usedForPeriodCalculation", type logical}, {"loanCardURL", type text}, {"lastDateModified", type date}, {"lastDateTimeModified", type datetime}, {"hideFromWeb", type logical}, {"systemCreated", type logical}, {"systemModifiedAt", type datetime}, {"systemCreatedAt", type datetime}, {"systemRowVersion", Int64.Type} }),
#"Added custom" = Table.AddColumn(#"Changed column type", "Region99999", each "99999", type text), #"Inserted conditional column" = Table.AddColumn(#"Added custom", "LastDateModMin2000", each if [lastDateModified] < #date(2000, 1, 1) then #date(2000, 1, 1) else [lastDateModified], type date),
// Add composite key for Value Entries ValueEntriesWithKey = Table.AddColumn(#"Inserted conditional column", "CompositeKey", each "VE_" & Text.From([entryNo]), type text),
// Add source type ValueEntriesWithSource = Table.AddColumn(ValueEntriesWithKey, "SourceType", each "ValueEntry", type text),
// Add null JournalLineNo for ValueEntries ValueEntriesWithLineNo = Table.AddColumn(ValueEntriesWithSource, "JournalLineNo", each null, type nullable number) in ValueEntriesWithLineNo; shared BC_Combined = let Source = Table.Combine({BC_CommissionValues, BC_JournalLines}),
// On first run ever, Dataverse table will not even exist BranchLookupExists = try lv_lvcompbranch is table otherwise false, LoanOfficerLookupExists = try lv_lvcomploanofficer is table otherwise false,
BranchLookup = if BranchLookupExists then lv_lvcompbranch else null, LoanOfficerLookup = if LoanOfficerLookupExists then lv_lvcomploanofficer else null,
// Branch Name lookup from branch code #"Added BranchName" = if BranchLookupExists then Table.AddColumn( Source, "branchName", each try ( let cleanCostCenter = Text.Trim(Text.From([costCenterCode])), lookupResult = Table.SelectRows(BranchLookup, each Text.Trim(Text.From([lv_code])) = cleanCostCenter) in if Table.RowCount(lookupResult) > 0 then lookupResult{0}[lv_name] else "" ) otherwise "", type text ) else Table.AddColumn(Source, "branchName", each "", type text),
// Loan Officer Name lookup from loan officer code #"Updated LoanOfficerName" = if LoanOfficerLookupExists then Table.TransformColumns( #"Added BranchName", {{"loanOfficerName", each if Text.Trim(_) = "" or _ = null then try ( let cleanLoanOfficerCode = Text.Trim(Text.From([loanOfficerCode])), lookupResult = Table.SelectRows(LoanOfficerLookup, each Text.Trim(Text.From([lv_code])) = cleanLoanOfficerCode) in if Table.RowCount(lookupResult) > 0 then lookupResult{0}[lv_name] else _ ) otherwise _ else _ }} ) else #"Added BranchName" in #"Updated LoanOfficerName"; shared DebtLogValueEntry = let Source = OData.Feed(OData_BASEUrl & "debtLogValueEntries", null, [Implementation = "2.0"]) in Source; shared CommissionSetup = let Source = OData.Feed(OData_BASEUrl & "CommissionSetup", null, [Implementation = "2.0"]) in Source;
